"use client";

import { useState } from "react";
import { createBrowserClient } from "@supabase/ssr";
import Link from "next/link";
import Image from "next/image";
import { useRouter } from "next/navigation";

export default function SignupPage() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [name, setName] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [confirmationSent, setConfirmationSent] = useState(false);
  const router = useRouter();

  const supabase = createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!
  );

  async function handleSignup(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    setError("");

    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        data: { full_name: name },
        emailRedirectTo: `${window.location.origin}/callback`,
      },
    });

    if (error) {
      setError(error.message);
      setLoading(false);
      return;
    }

    if (data.session) {
      // Immediate session (email confirmation disabled)
      router.push("/dashboard");
      router.refresh();
    } else {
      // Email confirmation required
      setError("");
      setConfirmationSent(true);
    }
  }

  async function handleGoogleSignup() {
    await supabase.auth.signInWithOAuth({
      provider: "google",
      options: { redirectTo: `${window.location.origin}/callback` },
    });
  }

  return (
    <div className="min-h-screen flex items-center justify-center bg-jungle-stage">
      <div className="w-full max-w-[440px] p-10 card-glass mx-4 sm:mx-0">
        <div className="flex justify-center mb-8">
          <Link href="/">
            <Image src="/assets/zikit-nav-logo.webp" alt="Zikit" width={120} height={40} className="h-9 w-auto" />
          </Link>
        </div>
        <h1 className="text-[28px] sm:text-[32px] font-bold text-center mb-2 text-[var(--text-cream)] tracking-tight">Create your account</h1>
        <p className="text-[var(--text-muted)] text-center mb-8">
          Start monitoring pages in 30 seconds
        </p>

        <button
          onClick={handleGoogleSignup}
          className="w-full flex items-center justify-center gap-2 px-4 py-2.5 border border-white/12 rounded-lg hover:bg-white/6 transition mb-6"
        >
          <svg className="w-5 h-5" viewBox="0 0 24 24">
            <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 0 1-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" />
            <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
            <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
            <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
          </svg>
          Continue with Google
        </button>

        <div className="relative mb-6">
          <div className="absolute inset-0 flex items-center">
            <div className="w-full border-t border-[var(--text-muted)]/20" />
          </div>
          <div className="relative flex justify-center text-sm">
            <span className="px-2 bg-[var(--bg-ink-2)] text-[var(--text-muted)]">or</span>
          </div>
        </div>

        {confirmationSent ? (
          <div className="text-center py-8">
            <div className="text-4xl mb-4">&#x2709;&#xFE0F;</div>
            <h2 className="text-xl font-semibold text-[var(--text-cream)] mb-2">Check your email</h2>
            <p className="text-[var(--text-muted)] mb-4">
              We sent a confirmation link to <strong className="text-[var(--text-cream)]">{email}</strong>.
              Click the link in your email to activate your account.
            </p>
            <button
              onClick={() => setConfirmationSent(false)}
              className="text-sm text-[var(--accent-jade)] hover:underline"
            >
              Try a different email
            </button>
          </div>
        ) : (
        <form onSubmit={handleSignup} className="space-y-4">
          <div>
            <label htmlFor="signup-name" className="block text-sm font-medium text-[var(--text-cream)] mb-1">Full name</label>
            <input
              id="signup-name"
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              required
              className="w-full px-3 py-2 border border-[var(--text-muted)]/30 bg-white/5 text-[var(--text-cream)] rounded-lg focus:outline-none focus:ring-2 focus:ring-[var(--accent-jade)] placeholder:text-[var(--text-muted)]/50"
              placeholder="Jane Smith"
            />
          </div>
          <div>
            <label htmlFor="signup-email" className="block text-sm font-medium text-[var(--text-cream)] mb-1">Email</label>
            <input
              id="signup-email"
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              className="w-full px-3 py-2 border border-[var(--text-muted)]/30 bg-white/5 text-[var(--text-cream)] rounded-lg focus:outline-none focus:ring-2 focus:ring-[var(--accent-jade)] placeholder:text-[var(--text-muted)]/50"
              placeholder="you@company.com"
            />
          </div>
          <div>
            <label htmlFor="signup-password" className="block text-sm font-medium text-[var(--text-cream)] mb-1">Password</label>
            <input
              id="signup-password"
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              minLength={8}
              className="w-full px-3 py-2 border border-[var(--text-muted)]/30 bg-white/5 text-[var(--text-cream)] rounded-lg focus:outline-none focus:ring-2 focus:ring-[var(--accent-jade)] placeholder:text-[var(--text-muted)]/50"
              placeholder="Min 8 characters"
            />
          </div>

          {error && <p className="text-sm text-red-400">{error}</p>}

          <button
            type="submit"
            disabled={loading}
            className="w-full py-2.5 btn-primary rounded-lg transition disabled:opacity-50"
          >
            {loading ? "Creating account..." : "Create account"}
          </button>
        </form>
        )}

        <p className="mt-4 text-center text-xs text-[var(--text-muted)] max-w-xs mx-auto leading-relaxed">
          By creating an account you agree to our{" "}
          <Link href="/terms" className="text-[var(--accent-jade)] hover:underline">Terms</Link>
          {" "}and{" "}
          <Link href="/privacy" className="text-[var(--accent-jade)] hover:underline">Privacy Policy</Link>.
        </p>
        <p className="mt-4 text-center text-sm text-[var(--text-muted)]">
          Already have an account?{" "}
          <Link href="/login" className="text-[var(--accent-jade)] hover:underline">
            Sign in
          </Link>
        </p>
      </div>
    </div>
  );
}
